class Solution {
public:
    vector<bool> friendRequests(int n, vector<vector<int>>& restrictions, vector<vector<int>>& requests) {
        vector<int> parent(n);
        for (int i = 0; i < n; ++i) parent[i] = i;
        vector<bool> result;

        for (auto& req : requests) {
            int u = req[0], v = req[1];
            if (find(parent, u) != find(parent, v)) {
                bool valid = true;
                for (auto& restrict : restrictions) {
                    int x = restrict[0], y = restrict[1];
                    if ((find(parent, u) == find(parent, x) && find(parent, v) == find(parent, y)) ||
                        (find(parent, u) == find(parent, y) && find(parent, v) == find(parent, x))) {
                        valid = false;
                        break;
                    }
                }
                if (valid) {
                    unionParent(parent, find(parent, u), find(parent, v));
                    result.push_back(true);
                } else {
                    result.push_back(false);
                }
            } else {
                result.push_back(true);
            }
        }
        return result;
    }

    int find(vector<int>& parent, int x) {
        if (parent[x] != x) parent[x] = find(parent, parent[x]);
        return parent[x];
    }

    void unionParent(vector<int>& parent, int x, int y) {
        int rootX = find(parent, x);
        int rootY = find(parent, y);
        if (rootX != rootY) parent[rootX] = rootY;
    }
};
